# Level-2 summarization: compress K consecutive L1 summaries into one L2
# L2 summaries are shorter (~100 tokens) and capture topic-level themes

def compress_to_l2(l1_summaries: list[str]) -> str:
    """Merge several L1 summaries into a single L2 summary."""
    combined = "\n\n---\n\n".join(l1_summaries)
    response = client.messages.create(
        model="claude-haiku-4-5-20251001",
        max_tokens=150,
        messages=[{"role": "user", "content": (
            "The following are summaries of consecutive conversation episodes. "
            "Merge them into a single 3–5 bullet summary, keeping only "
            "decisions, open questions, and factual outcomes:\n\n" + combined[:3000]
        )}],
    )
    return response.content[0].text

class L2Store:
    """Rolls up L1 summaries into L2 chunks every K episodes."""
    def __init__(self, chunk_size: int = 5):
        self.chunk_size = chunk_size
        self._pending: list[str] = []  # L1s not yet rolled up
        self.summaries: list[str] = []  # L2 summaries

    def ingest(self, l1_summary: str) -> None:
        self._pending.append(l1_summary)
        if len(self._pending) >= self.chunk_size:
            self.summaries.append(compress_to_l2(self._pending))
            self._pending = []

    def flush(self) -> None:
        if self._pending:
            self.summaries.append(compress_to_l2(self._pending))
            self._pending = []

# Level-3 distillation: extract the permanent skeleton from all L2 summaries
# L3 is a JSON object with decisions, open_questions, and known_facts
# It fits in ~50–80 tokens and stays in context throughout the session

import json

def distill_to_l3(l2_summaries: list[str]) -> dict:
    """Distill all L2 summaries into a compact JSON skeleton."""
    combined = "\n\n---\n\n".join(l2_summaries)
    response = client.messages.create(
        model="claude-haiku-4-5-20251001",
        max_tokens=200,
        messages=[{"role": "user", "content": (
            "Extract ONLY the most durable facts from these summaries. "
            "Return ONLY valid JSON with keys: "
            'decisions (list[str]), open_questions (list[str]), known_facts (list[str]). '+
            "Each list item must be a single short sentence.\n\n" + combined[:4000]
        )}],
    )
    try:
        return json.loads(response.content[0].text)
    except json.JSONDecodeError:
        # fallback: wrap raw text
        return {"decisions": [], "open_questions": [], "known_facts": [response.content[0].text]}

def l3_to_context_str(l3: dict) -> str:
    """Format L3 for injection into the system prompt."""
    parts = []
    if l3.get("decisions"):
        parts.append("Decisions: " + "; ".join(l3["decisions"]))
    if l3.get("open_questions"):
        parts.append("Open: " + "; ".join(l3["open_questions"]))
    if l3.get("known_facts"):
        parts.append("Facts: " + "; ".join(l3["known_facts"]))
    return "[Session skeleton]\n" + "\n".join(parts)
